import React from "react";

interface Props {
 id: number;
 name: string;
 weight: string;
 price: number;
 oldPrice?: number;
 discount?: string;
 image: string;
 onAdd: () => void;
}

const ProductCard: React.FC<Props> = ({ name, weight, price, oldPrice, discount, image, onAdd }) => (
 <div className="ux-p-card group reveal-anim h-full">

  {/* Image container */}
  <div className="img-box">
   {discount && (
    <span className="discount-badge">{discount}</span>
   )}
   <img
    src={image}
    alt={name}
    className="w-[85%] h-[85%] object-contain mix-blend-multiply"
    loading="lazy"
   />
  </div>

  {/* Info */}
  <div className="flex flex-col flex-1">
   <p className="product-name line-clamp-2 min-h-[38px]">{name}</p>
   <p className="product-weight">{weight}</p>

   {/* Price row */}
   <div className="mt-auto pt-3 flex items-end justify-between">
    <div className="flex flex-col">
     {oldPrice && (
      <span className="product-old-price">{oldPrice} ₽</span>
     )}
     <span className="product-price">{price} ₽</span>
    </div>

    <button
     onClick={(e) => { e.stopPropagation(); onAdd(); }}
     className="pink-plus shadow-sm"
     title="В корзину"
     aria-label="Добавить в корзину"
    >
     <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round">
      <path d="M12 5v14M5 12h14" />
     </svg>
    </button>
   </div>

   <div className="card-accent-line" />
  </div>
 </div>
);

export default ProductCard;
